421	        let automatic = OutputPolicy::ExternalLinkAllowed {
422	            request_nvvm_ir: false,
423	        };
424	        let requested = OutputPolicy::ExternalLinkAllowed {
425	            request_nvvm_ir: true,
426	        };
427	        assert!(!should_emit_nvvm_ir(automatic, false));
428	        assert!(should_emit_nvvm_ir(automatic, true));
429	        assert!(should_emit_nvvm_ir(requested, false));
