1	/*
2	 * SPDX-FileCopyrightText: Copyright (c) 2026 NVIDIA CORPORATION & AFFILIATES. All rights reserved.
3	 * SPDX-License-Identifier: Apache-2.0
4	 */
5	
6	use crate::error::PipelineError;
7	use crate::export::DeviceExternDecl;
8	use llvm_export::export::DeviceExternType;
9	use pliron::builtin::op_interfaces::SymbolOpInterface;
10	use pliron::context::{Context, Ptr};
11	use pliron::linked_list::ContainsLinkedList;
12	use pliron::op::Op;
13	use pliron::operation::Operation;
14	use pliron::printable::Printable;
15	
16	/// Inserts a function operation into the module's block.
17	// mir-importer pipeline plumbing; not part of the frontend contract.
18	#[doc(hidden)]
19	pub fn append_to_module(ctx: &Context, module_op_ptr: Ptr<Operation>, func_op_ptr: Ptr<Operation>) {
20	    let region = module_op_ptr.deref(ctx).get_region(0).deref(ctx);
21	    let block = region.iter(ctx).next().expect("Module should have a block");
22	    func_op_ptr.insert_at_back(block, ctx);
23	}
24	
25	/// Lowers `dialect-mir` operations to the LLVM dialect.
26	///
27	/// Runs `mir-lower`'s `DialectConversion`-based pass, which converts each
28	/// `dialect-mir`/`dialect-nvvm` op to its LLVM dialect equivalent. The LLVM
29	/// dialect auto-registers when the `Context` is created, so no explicit
30	/// registration is needed here.
31	// mir-importer pipeline plumbing; not part of the frontend contract.
32	#[doc(hidden)]
33	pub fn lower_to_llvm(
34	    ctx: &mut Context,
35	    module_op_ptr: Ptr<Operation>,
36	    allow_fma_contraction: bool,
37	) -> Result<(), PipelineError> {
38	    mir_lower::register(ctx);
39	
40	    match mir_lower::lower_mir_to_llvm_with_options(
41	        ctx,
42	        module_op_ptr,
43	        mir_lower::LoweringOptions {
44	            allow_fma_contraction,
45	        },
46	    ) {
47	        Ok(()) => Ok(()),
48	        // Format with `ctx` so the failing op's location/span survives.
49	        Err(e) => Err(PipelineError::Lowering(e.disp(ctx).to_string())),
50	    }
51	}
52	
53	/// Adds device extern function declarations to the LLVM dialect module.
54	///
55	/// Creates LLVM dialect `FuncOp` declarations (without bodies) for each
56	/// device extern function. These declarations ensure that calls to extern
57	/// functions pass verification; the matching `declare` statements with
58	/// attributes are emitted during LLVM IR export.
59	///
60	/// This runs before MIR-to-LLVM call lowering so the call converter can read
61	/// exact parameter address spaces. It is still idempotent with respect to any
62	/// LLVM declaration already present in the mixed module; inserting a second
63	/// `FuncOp` for the same symbol would fail module verification.
64	// mir-importer pipeline plumbing; not part of the frontend contract.
65	#[doc(hidden)]
66	pub fn add_device_extern_declarations(
67	    ctx: &mut Context,
68	    module_op_ptr: Ptr<Operation>,
69	    device_externs: &[DeviceExternDecl],
70	) -> Result<(), PipelineError> {
71	    use llvm_export::ops::FuncOp;
72	    use llvm_export::types::FuncType;
73	    use pliron::builtin::type_interfaces::FunctionTypeInterface;
74	    use pliron::identifier::Identifier;
75	    use std::collections::HashMap;
76	
77	    // Get the module's block pointer first (this is a Ptr, not a Ref, so no borrow issues)
78	    let block = {
79	        let region = module_op_ptr.deref(ctx).get_region(0).deref(ctx);
80	        region.iter(ctx).next().expect("Module should have a block")
81	    };
82	
83	    let declared_symbols: HashMap<_, _> = block
84	        .deref(ctx)
85	        .iter(ctx)
86	        .filter_map(|op| {
87	            Operation::get_op::<FuncOp>(op, ctx)
88	                .map(|f| (f.get_symbol_name(ctx).to_string(), f.get_type(ctx)))
89	        })
90	        .collect();
91	
92	    for decl in device_externs {
93	        let param_types: Vec<_> = decl
94	            .param_types
95	            .iter()
96	            .map(|ty| device_extern_type_to_pliron(ctx, ty, false))
97	            .collect::<Result<_, _>>()?;
98	        let return_type = device_extern_type_to_pliron(ctx, &decl.return_type, true)?;
99	
100	        // Create function type (result, args, is_variadic)
101	        let func_type = FuncType::get(ctx, return_type, param_types, false);
102	
103	        if let Some(existing_type) = declared_symbols.get(&decl.export_name) {
104	            let existing_ref = existing_type.deref(ctx);
105	            let existing = &*existing_ref;
106	            let expected_ref = func_type.deref(ctx);
107	            let expected = &*expected_ref;
108	            if existing.result_type() != expected.result_type()
109	                || existing.arg_types() != expected.arg_types()
110	                || existing.is_var_arg() != expected.is_var_arg()
111	            {
112	                return Err(PipelineError::Export(format!(
113	                    "device extern `@{}` conflicts with the call-site declaration: expected `{}`, found `{}`",
114	                    decl.export_name,
115	                    expected_ref.disp(ctx),
116	                    existing_ref.disp(ctx),
117	                )));
118	            }
119	            continue;
120	        }
121	
122	        // Use the original export name (NOT the prefixed name).
123	        // The MIR sees calls to `cuda_oxide_device_extern_<hash>_foo`, but
124	        // mir-lower/convert/ops/call.rs strips the reserved prefix via
125	        // `reserved_oxide_symbols::device_extern_base_name`, so the LLVM IR
126	        // emits `call @foo(...)`. For that to resolve, we declare `@foo` here.
127	        let func_ident: Identifier = decl.export_name.clone().try_into().map_err(|_| {
128	            PipelineError::Export(format!(
129	                "device-extern symbol `{}` cannot be represented by the LLVM dialect",
130	                decl.export_name
131	            ))
132	        })?;
133	
134	        // Create function declaration (no body = declaration)
135	        let func_op = FuncOp::new(ctx, func_ident, func_type);
136	
137	        // Insert at the front of the module (declarations come before definitions)
138	        func_op.get_operation().insert_at_front(block, ctx);
139	    }
140	
141	    Ok(())
142	}
143	
144	/// Convert the structured device-extern ABI type to the opaque-pointer pliron
145	/// LLVM type used for verification and call lowering.
146	fn device_extern_type_to_pliron(
147	    ctx: &mut Context,
148	    ty: &DeviceExternType,
149	    allow_void: bool,
